/**
 * recenter-spritesheet.mjs — Reprocess existing pet spritesheets to fix centering jitter
 * and normalize cat size across all behaviors.
 *
 * Problem: Spritesheets generated by generate-pet-spritesheet.mjs had inconsistent frame
 * centering (cat shifts position between frames) and different cat sizes across behaviors.
 *
 * Solution: For each frame, find content bounds, scale to a uniform target height, then
 * bottom-align and horizontally center on a clean transparent cell canvas.
 *
 * Usage:
 *   node sprite-gen/scripts/recenter-spritesheet.mjs --species cat
 *   node sprite-gen/scripts/recenter-spritesheet.mjs --species cat --behavior sit
 *   node sprite-gen/scripts/recenter-spritesheet.mjs --species cat --target-height 50
 *
 * Options:
 *   --species        (required) Pet species name
 *   --behavior       (optional) Process only one behavior; omit to process ALL behaviors
 *   --target-height  (optional) Target content height in px; defaults to walk spritesheet avg
 *   --frame-size     (optional, default 64) Output frame cell size in px
 */

import { readFile, writeFile } from 'node:fs/promises';
import { existsSync } from 'node:fs';
import { dirname, join, resolve } from 'node:path';
import { parseArgs } from 'node:util';
import { fileURLToPath } from 'node:url';

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);
const PROJECT_ROOT = resolve(__dirname, '../..');

/** Bottom padding in px applied when placing frame content on the cell. */
const BOTTOM_PADDING = 2;

/**
 * Alpha threshold: pixels with alpha <= this value are treated as transparent
 * when computing content bounding boxes.
 */
const ALPHA_THRESHOLD = 10;

/**
 * Cat animation frame counts — mirrors petAnimations.ts.
 * Hardcoded here to avoid importing TypeScript at runtime.
 */
const FRAME_COUNTS = {
  idle: 6,
  walk: 8,
  sit: 4,
  lick: 6,
  sleep: 4,
  react: 4,
};

// ---------------------------------------------------------------------------
// Dependency check
// ---------------------------------------------------------------------------

let sharp;
try {
  sharp = (await import('sharp')).default;
} catch {
  console.error(
    '\n[ERROR] "sharp" is not installed.\n' +
      '  Run:  npm install sharp\n' +
      '  Then re-run this script.\n'
  );
  process.exit(1);
}

// ---------------------------------------------------------------------------
// CLI parsing
// ---------------------------------------------------------------------------

const { values: args } = parseArgs({
  options: {
    species:         { type: 'string' },
    behavior:        { type: 'string' },
    'target-height': { type: 'string' },
    'frame-size':    { type: 'string', default: '64' },
    help:            { type: 'boolean', short: 'h', default: false },
  },
  strict: true,
  allowPositionals: false,
});

if (args.help || !args.species) {
  console.log(`
Usage: node sprite-gen/scripts/recenter-spritesheet.mjs [options]

Required:
  --species <name>          Pet species name (e.g. "cat")

Optional:
  --behavior <name>         Process only one behavior (idle, walk, sit, lick, sleep, react)
                            If omitted, ALL behaviors are processed.
  --target-height <px>      Target content height in pixels. All frames will be scaled so
                            the cat content is exactly this many pixels tall.
                            Default: auto-detected from the walk spritesheet average.
  --frame-size <px>         Output frame cell size (default: 64)
  --help, -h                Show this help message
  `);
  process.exit(args.help ? 0 : 1);
}

const SPECIES = args.species;
const SINGLE_BEHAVIOR = args.behavior ?? null;
const FRAME_SIZE = parseInt(args['frame-size'] ?? '64', 10);
const EXPLICIT_TARGET_HEIGHT = args['target-height'] ? parseInt(args['target-height'], 10) : null;

// ---------------------------------------------------------------------------
// Utilities
// ---------------------------------------------------------------------------

/**
 * Returns the absolute path to a behavior spritesheet PNG for a given species.
 *
 * @param {string} species
 * @param {string} behavior
 * @returns {string}
 */
function spritesheetPath(species, behavior) {
  return join(PROJECT_ROOT, 'public/assets/camp/pets', species, `${behavior}.png`);
}

/**
 * Find the tight content bounding box within a single RGBA frame buffer.
 * Returns null if the frame contains no visible pixels.
 *
 * @param {Buffer} rawPixels - Raw RGBA pixel data
 * @param {number} width - Frame width in pixels
 * @param {number} height - Frame height in pixels
 * @returns {{ minX: number, minY: number, maxX: number, maxY: number,
 *             contentWidth: number, contentHeight: number } | null}
 */
function findContentBounds(rawPixels, width, height) {
  let minX = width;
  let minY = height;
  let maxX = -1;
  let maxY = -1;

  for (let y = 0; y < height; y++) {
    for (let x = 0; x < width; x++) {
      const idx = (y * width + x) * 4;
      const alpha = rawPixels[idx + 3];
      if (alpha > ALPHA_THRESHOLD) {
        if (x < minX) minX = x;
        if (x > maxX) maxX = x;
        if (y < minY) minY = y;
        if (y > maxY) maxY = y;
      }
    }
  }

  if (maxX < 0) return null; // Fully transparent frame

  return {
    minX,
    minY,
    maxX,
    maxY,
    contentWidth: maxX - minX + 1,
    contentHeight: maxY - minY + 1,
  };
}

/**
 * Create a fully transparent cell buffer of frameSize × frameSize.
 *
 * @param {number} frameSize
 * @returns {Promise<Buffer>}
 */
async function createEmptyCell(frameSize) {
  return sharp({
    create: {
      width: frameSize,
      height: frameSize,
      channels: 4,
      background: { r: 0, g: 0, b: 0, alpha: 0 },
    },
  })
    .png()
    .toBuffer();
}

/**
 * Processes a single frame buffer: extracts content, scales to targetHeight,
 * then centers horizontally and bottom-aligns on a transparent cell canvas.
 *
 * If the scaled width would exceed frameSize (wide-stance poses), the content
 * is proportionally scaled down so it fits within the cell while keeping the
 * aspect ratio intact.
 *
 * @param {Buffer} framePng - PNG buffer of the isolated frame
 * @param {number} targetHeight - Desired content height in output pixels
 * @param {number} frameSize - Square cell dimension
 * @returns {Promise<Buffer>} PNG buffer for the recentered cell
 */
async function processFrame(framePng, targetHeight, frameSize) {
  // Decode to raw RGBA
  const { data: rawPixels, info } = await sharp(framePng)
    .ensureAlpha()
    .raw()
    .toBuffer({ resolveWithObject: true });

  const { width, height } = info;
  const bounds = findContentBounds(rawPixels, width, height);

  if (!bounds) {
    // Fully transparent — return empty cell
    return createEmptyCell(frameSize);
  }

  // Extract tight content region from PNG
  let content = await sharp(framePng)
    .extract({
      left: bounds.minX,
      top: bounds.minY,
      width: bounds.contentWidth,
      height: bounds.contentHeight,
    })
    .png()
    .toBuffer();

  // Scale to target height using nearest-neighbor to preserve pixel art crispness
  let scale = targetHeight / bounds.contentHeight;
  let newW = Math.max(1, Math.round(bounds.contentWidth * scale));
  let newH = Math.max(1, Math.round(bounds.contentHeight * scale));

  // If scaled width overflows the cell, scale down proportionally so both
  // dimensions fit. This handles wide-stance poses (e.g. mid-walk legs spread).
  const maxContentWidth = frameSize; // no horizontal margin — use full cell width
  if (newW > maxContentWidth) {
    scale = maxContentWidth / bounds.contentWidth;
    newW = maxContentWidth;
    newH = Math.max(1, Math.round(bounds.contentHeight * scale));
  }

  content = await sharp(content)
    .resize(newW, newH, { kernel: sharp.kernel.nearest, fit: 'fill' })
    .png()
    .toBuffer();

  // Bottom-align with 2px padding; center horizontally.
  // Clamp placement so content never overflows the cell boundaries.
  const placeX = Math.max(0, Math.min(frameSize - newW, Math.round((frameSize - newW) / 2)));
  const placeY = Math.max(0, Math.min(frameSize - newH, frameSize - newH - BOTTOM_PADDING));

  return sharp({
    create: {
      width: frameSize,
      height: frameSize,
      channels: 4,
      background: { r: 0, g: 0, b: 0, alpha: 0 },
    },
  })
    .composite([{ input: content, left: placeX, top: placeY }])
    .png()
    .toBuffer();
}

/**
 * Splits a horizontal spritesheet PNG into individual frame buffers.
 *
 * @param {Buffer} spritesheetPng - Full spritesheet PNG buffer
 * @param {number} frameCount - Number of frames in the strip
 * @returns {Promise<Buffer[]>} Array of per-frame PNG buffers
 */
async function splitIntoFrames(spritesheetPng, frameCount) {
  const meta = await sharp(spritesheetPng).metadata();
  const totalWidth = meta.width;
  const frameWidth = Math.floor(totalWidth / frameCount);
  const frameHeight = meta.height;

  const frames = [];
  for (let i = 0; i < frameCount; i++) {
    const frameBuf = await sharp(spritesheetPng)
      .extract({
        left: i * frameWidth,
        top: 0,
        width: frameWidth,
        height: frameHeight,
      })
      .png()
      .toBuffer();
    frames.push(frameBuf);
  }
  return frames;
}

/**
 * Measure the average content height across all frames of a spritesheet.
 * Used to auto-detect the reference height from the walk animation.
 *
 * @param {string} pngPath - Path to the spritesheet PNG
 * @param {number} frameCount - Number of frames in the strip
 * @returns {Promise<number>} Average content height in pixels
 */
async function measureAverageContentHeight(pngPath, frameCount) {
  const buf = await readFile(pngPath);
  const frames = await splitIntoFrames(buf, frameCount);

  let totalHeight = 0;
  let counted = 0;

  for (const frame of frames) {
    const { data: rawPixels, info } = await sharp(frame)
      .ensureAlpha()
      .raw()
      .toBuffer({ resolveWithObject: true });

    const bounds = findContentBounds(rawPixels, info.width, info.height);
    if (bounds) {
      totalHeight += bounds.contentHeight;
      counted++;
    }
  }

  if (counted === 0) {
    throw new Error(`No visible content found in ${pngPath}`);
  }

  return Math.round(totalHeight / counted);
}

/**
 * Reprocess a single behavior spritesheet: load, split, recenter each frame,
 * assemble, and write PNG + WebP output.
 *
 * @param {string} species
 * @param {string} behavior
 * @param {number} targetHeight
 * @param {number} frameSize
 */
async function processBehavior(species, behavior, targetHeight, frameSize) {
  const frameCount = FRAME_COUNTS[behavior];
  if (!frameCount) {
    console.warn(`  [SKIP] Unknown behavior "${behavior}" — no frame count defined`);
    return;
  }

  const pngPath = spritesheetPath(species, behavior);
  if (!existsSync(pngPath)) {
    console.warn(`  [SKIP] File not found: ${pngPath}`);
    return;
  }

  console.log(`  Processing ${behavior} (${frameCount} frames, targetHeight=${targetHeight}px)...`);

  const spritesheetBuf = await readFile(pngPath);
  const frames = await splitIntoFrames(spritesheetBuf, frameCount);

  // Process each frame
  const processedFrames = [];
  for (let i = 0; i < frames.length; i++) {
    const cell = await processFrame(frames[i], targetHeight, frameSize);
    processedFrames.push(cell);
    process.stdout.write(`    frame ${i + 1}/${frames.length}\r`);
  }
  process.stdout.write('\n');

  // Assemble horizontal strip
  const totalWidth = frameSize * frameCount;
  const compositeInputs = processedFrames.map((buf, idx) => ({
    input: buf,
    left: idx * frameSize,
    top: 0,
  }));

  const assembledPng = await sharp({
    create: {
      width: totalWidth,
      height: frameSize,
      channels: 4,
      background: { r: 0, g: 0, b: 0, alpha: 0 },
    },
  })
    .composite(compositeInputs)
    .png()
    .toBuffer();

  // Convert to WebP
  const assembledWebp = await sharp(assembledPng)
    .webp({ quality: 90, effort: 6 })
    .toBuffer();

  // Write outputs (overwrite in place)
  const webpPath = pngPath.replace(/\.png$/, '.webp');
  await writeFile(pngPath, assembledPng);
  await writeFile(webpPath, assembledWebp);

  const pngKb = (assembledPng.length / 1024).toFixed(1);
  const webpKb = (assembledWebp.length / 1024).toFixed(1);
  console.log(`  [OK] ${behavior}: ${totalWidth}x${frameSize} — PNG ${pngKb}KB, WebP ${webpKb}KB`);
}

// ---------------------------------------------------------------------------
// Main
// ---------------------------------------------------------------------------

console.log(`\nRecenter Spritesheet — species: ${SPECIES}`);
console.log(`  frame-size: ${FRAME_SIZE}px`);

// Resolve target height
let targetHeight = EXPLICIT_TARGET_HEIGHT;

if (!targetHeight) {
  // Auto-detect from walk spritesheet
  const walkPath = spritesheetPath(SPECIES, 'walk');
  if (!existsSync(walkPath)) {
    console.error(
      `[ERROR] Cannot auto-detect target height — walk spritesheet not found at:\n  ${walkPath}\n` +
        '  Either provide --target-height or ensure walk.png exists.'
    );
    process.exit(1);
  }
  console.log(`  Auto-detecting target height from walk spritesheet...`);
  targetHeight = await measureAverageContentHeight(walkPath, FRAME_COUNTS.walk);
  console.log(`  Detected walk avg content height: ${targetHeight}px`);
} else {
  console.log(`  Using explicit target height: ${targetHeight}px`);
}

// Determine which behaviors to process
const behaviorsToProcess = SINGLE_BEHAVIOR
  ? [SINGLE_BEHAVIOR]
  : Object.keys(FRAME_COUNTS);

console.log(`  Behaviors: ${behaviorsToProcess.join(', ')}\n`);

for (const behavior of behaviorsToProcess) {
  await processBehavior(SPECIES, behavior, targetHeight, FRAME_SIZE);
}

console.log('\nDone.\n');
